/**
 * Implementation of a MinPriorityQueue needed for Dijkstra's algorithm.
 * It stores elements as [priority, value].
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    size() {
        return this.heap.length;
    }

    isEmpty() {
        return this.size() === 0;
    }

    getParentIndex(i) { return Math.floor((i - 1) / 2); }
    getLeftChildIndex(i) { return 2 * i + 1; }
    getRightChildIndex(i) { return 2 * i + 2; }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    // Compares two elements [p1, v1] and [p2, v2] based on priority (p).
    compare(i, j) {
        // We compare by the first element (priority/cost)
        return this.heap[i][0] < this.heap[j][0];
    }

    bubbleUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = this.getParentIndex(currentIndex);
            if (this.compare(currentIndex, parentIndex)) {
                this.swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    bubbleDown(index) {
        let currentIndex = index;
        const size = this.size();

        while (true) {
            const left = this.getLeftChildIndex(currentIndex);
            const right = this.getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            // Check left child
            if (left < size && this.compare(left, smallest)) {
                smallest = left;
            }

            // Check right child
            if (right < size && this.compare(right, smallest)) {
                smallest = right;
            }

            if (smallest !== currentIndex) {
                this.swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }

    insert(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    extractMin() {
        if (this.isEmpty()) return null;
        if (this.size() === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return min;
    }
}


function solve(n, edges, source, target, k) {
    if (source === target) return 0;

    // Build adjacency list: adj[u] = [[v1, w1], [v2, w2], ...]
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        adj[v].push([u, w]);
    }

    /**
     * Checks if a path exists from source to target using at most k heavy edges
     * for a given threshold T.
     * @param {number} T The threshold.
     * @returns {boolean} True if a valid path exists, false otherwise.
     */
    const canReach = (T) => {
        // D[i] stores the minimum number of heavy edges to reach node i
        const D = Array(n).fill(Infinity);
        D[source] = 0;

        // Priority Queue stores [heavy_edge_count, node]
        const pq = new MinPriorityQueue();
        pq.insert([0, source]);

        while (!pq.isEmpty()) {
            const [d, u] = pq.extractMin();

            if (d > D[u]) {
                continue;
            }

            if (u === target) {
                // Found shortest path in terms of heavy edges
                return d <= k;
            }

            // Optimization: If current heavy count already exceeds k, we can prune this path
            if (d > k) {
                continue;
            }

            for (const [v, w] of adj[u]) {
                // Cost is 1 if heavy (w > T), 0 if light (w <= T)
                const cost = (w > T) ? 1 : 0;
                const newDist = d + cost;

                if (newDist < D[v]) {
                    D[v] = newDist;
                    pq.insert([newDist, v]);
                }
            }
        }

        // Target unreachable or minimum heavy edge count exceeds k
        return D[target] <= k;
    };

    // Binary Search for the minimum threshold T.
    // Search range: [L, R]. Weights are up to 10^9.
    // We search up to 10^9 + 1 to ensure all possible thresholds are covered,
    // where 10^9 + 1 guarantees all edges are light (if they exist).
    let L = 0;
    // Max possible weight is 10^9. A threshold of 10^9 ensures all edges are light.
    // We use 10^9 + 1 as the upper bound for the search space boundary R.
    let R = 1000000001; 
    let minThreshold = -1;

    while (L < R) {
        // Use floor division for midpoint
        const M = L + Math.floor((R - L) / 2);

        if (canReach(M)) {
            // M works. This is a potential answer. Try to find a smaller one.
            minThreshold = M;
            R = M;
        } else {
            // M does not work. We need a larger threshold to make more edges light.
            L = M + 1;
        }
    }

    return minThreshold;
}

