use std::collections::BinaryHeap;
use std::cmp::Reverse;

// Helper structure for Dijkstra's: (cost, node)
// We use Reverse to make BinaryHeap act as a Min-Heap on cost.
type State = (Reverse<i64>, i64);

fn solve(n: i64, edges: Vec<Vec<i64>>, source: i64, target: i64, k: i64) -> i64 {
    if source == target {
        return 0;
    }

    // Adjacency list: adj[u] = Vec<(v, w)>
    let n_usize = n as usize;
    let mut adj: Vec<Vec<(i64, i64)>> = vec![vec![]; n_usize];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2];
        adj[u].push((v as i64, w));
        adj[v].push((u as i64, w));
    }

    /**
     * Checks if a path exists from source to target using at most k heavy edges
     * for a given threshold T.
     * @param T The threshold.
     * @returns True if a valid path exists, false otherwise.
     */
    let can_reach = |T: i64| -> bool {
        // D[i] stores the minimum number of heavy edges to reach node i
        let mut d: Vec<i64> = vec![k + 1; n_usize];
        d[source as usize] = 0;

        // Priority Queue stores (Reverse(heavy_edge_count), node_id)
        let mut pq: BinaryHeap<State> = BinaryHeap::new();
        pq.push((Reverse(0), source));

        while let Some((Reverse(d_u), u)) = pq.pop() {

            if d_u > d[u as usize] {
                continue;
            }

            if u == target {
                return d_u <= k;
            }

            // Pruning: if current heavy count already exceeds k, we can stop processing this path.
            if d_u > k {
                continue;
            }

            for (v, w) in &adj[u as usize] {
                // Cost is 1 if heavy (w > T), 0 if light (w <= T)
                let cost = if *w > T { 1 } else { 0 };
                let new_dist = d_u + cost;

                if new_dist <= k && new_dist < d[*v as usize] {
                    d[*v as usize] = new_dist;
                    pq.push((Reverse(new_dist), *v));
                }
            }
        }

        // Target unreachable or minimum heavy edge count exceeds k
        d[target as usize] <= k
    };

    // Binary Search for the minimum threshold T.
    // Search range: [L, R]. Weights are up to 10^9.
    // L starts at 0.
    // R must be large enough to cover all possibilities. Since max weight is 10^9, R = 10^9 + 1 ensures all edges are light.
    let mut L: i64 = 0;
    let mut R: i64 = 1_000_000_001; 
    let mut min_threshold: i64 = -1;

    while L < R {
        // M = L + (R - L) / 2
        let M = L + (R - L) / 2;

        if can_reach(M) {
            // M works. This is a potential answer. Try to find a smaller one.
            min_threshold = M;
            R = M;
        } else {
            // M does not work. We need a larger threshold to make more edges light.
            L = M + 1;
        }
    }

    min_threshold
