        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2];
        adj[u].push((v, w));
        adj[v].push((u, w));
    }

    // Function to check if a path exists using at most k heavy edges for a given threshold T
    let can_reach = |T: i64| -> bool {
        // D[i] stores the minimum number of heavy edges to reach node i
        // We use k+1 as infinity since k is the max allowed, and anything higher means failure.
        // However, using i64::MAX/2 is safer for Dijkstra's structure.
        let mut d: Vec<i64> = vec![i64::MAX / 2; n_usize];
