    // Search range: [L, R]. Weights are up to 10^9.
    // L starts at 0. R is set to 10^9 + 1 to ensure all weights are considered/handled.
    let mut l: i64 = 0;
    let mut r: i64 = 1_000_000_000 + 1; 
