use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Custom struct for priority queue elements: (cost, node)
// We implement Ord/PartialOrd to make BinaryHeap act as a MinHeap based on cost.
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: i64, // Number of heavy edges used (priority)
    node: i64, // Current node
}

// Implement comparison traits for Min-Heap behavior
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // BinaryHeap is a MaxHeap, so we reverse the natural ordering of cost
        // to achieve a MinHeap behavior on cost.
        other.cost.cmp(&self.cost)
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

